        delta.retain(3);
        delta.retain(2);
        assert.deepEqual(delta.ops, [{ retain: 5 }]);
        done();
    });

    it('should chop trailing retain without attributes', function(done) {
        const delta = new quill_delta();
        delta.insert('hello');
        delta.retain(5);
        delta.chop();
        assert.deepEqual(delta.ops, [{ insert: 'hello' }]);
        done();
    });

    it('should not chop retain with attributes', function(done) {
